## Binary Search Tree (BST)

A **Binary Search Tree** is a tree data structure where each node has at most two children, and for any node, all values in its left subtree are smaller and all values in its right subtree are larger. This ordering property enables efficient O(log n) average-time lookups, insertions, and deletions. BSTs are fundamental building blocks for implementing associative arrays, priority queues, and efficient search operations.

Here's a simple Python implementation:

```python
class Node:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, val):
        if not self.root:
            self.root = Node(val)
        else:
            self._insert(self.root, val)

    def _insert(self, node, val):
        if val < node.val:
            if node.left:
                self._insert(node.left, val)
            else:
                node.left = Node(val)
        else:
            if node.right:
                self._insert(node.right, val)
            else:
                node.right = Node(val)

    def search(self, val):
        node = self.root
        while node:
            if val == node.val:
                return True
            elif val < node.val:
                node = node.left
            else:
                node = node.right
        return False

    def inorder(self):
        """Returns sorted values (inorder traversal)"""
        result = []
        def dfs(node):
            if node:
                dfs(node.left)
                result.append(node.val)
                dfs(node.right)
        dfs(self.root)
        return result

# Usage example
bst = BST()
bst.insert(10)
bst.insert(5)
bst.insert(15)
bst.insert(3)
bst.insert(7)

print(bst.search(7))   # True
print(bst.search(12))  # False
print(bst.inorder())   # [3, 5, 7, 10, 15] — always sorted!
```
